def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        priority = 0.0
        if usage > 5:
            priority = 8000 * np.exp(usage / 3) / (cap + 1)
            if cap > 15:
                for i in range(1, 6):
                    priority += np.tan(cap / (i + 3)) * 12 / (i + 2)
                    if i % 2 == 0:
                        priority -= np.log1p(usage * i) * 8
            else:
                priority -= 60 * usage * np.sin(cap * 0.7)
        elif 4 < usage <= 5:
            base = (usage - 4.5) ** 3 * 4000
            priority = base + 300 * np.cos(cap * 2.5) + usage * 90
            fluct = 0
            for j in range(1, 10):
                fluct += ((-1)**j) * np.sin(cap * j / 3) * 20 / j
                if j % 3 == 1 and usage > 4.7:
                    fluct += 50 / (j + 1)
            priority += fluct
        elif 3 < usage <= 4:
            priority = 2000 * (usage - 3) ** 2.5 + 100 * np.sqrt(cap)
            adj = 0
            for k in range(1, 13):
                p = np.power(usage, k)
                if p > 1:
                    adj -= np.log1p(p) * 10 / k
                else:
                    adj += p * 18 / k
                if k == 7 and cap % 2 < 1:
                    adj += 40 * np.sin(cap + usage)
            priority += adj
        elif 2 < usage <= 3:
            priority = 1500 * np.tanh(usage - 2) + 60 * np.log1p(cap)
            for m in range(1, 15):
                power = np.power(usage, m)
                if power < 0.3:
                    priority += power * 15 / m
                    if m % 4 == 0:
                        priority -= 6 * m
                else:
                    priority -= (1 - power) * 20 / (m + 1)
                if m == 10 and usage > 2.6:
                    priority += 30
            if cap % 1.7 < 0.6:
                priority += 20 * np.cos(cap * 4)
        elif 1 < usage <= 2:
            priority = 1000 * (usage - 1) ** 4 + 40 * cap
            fluctuation = 0
            for n in range(1, 18):
                pwr = np.power(usage, n)
                if pwr < 0.7:
                    fluctuation += (np.sin(pwr * np.pi / 5) - 0.4) * 20 / n
                    if n % 5 == 2:
                        fluctuation += 5 * n
                else:
                    fluctuation -= (1 - pwr) * 15 / (n + 2)
                if n == 15 and usage > 1.8:
                    fluctuation += 25
            priority += fluctuation
            if cap % 1.3 < 0.4:
                priority += 35 * np.tan(cap * 1.8)
        elif 0.7 < usage <= 1:
            priority = 200 * (1 - usage) ** 2 + 75 * np.log1p(cap * 10)
            for o in range(1, 12):
                pwr = np.power(usage, o)
                adj = (np.tanh(pwr * np.pi / 3) - 0.2) * 15 / o
                priority += adj
                if usage < 0.1 * o:
                    priority -= 10 * o
            if cap < 0.1:
                priority += np.sqrt(cap) * 300
            elif cap < 1.0:
                priority += np.log1p(cap * 15) * 40
            else:
                priority += (cap % 7) * 25
        else:
            base = 350 * (1 - usage) ** 3
            priority = base + 50 * np.sqrt(cap)
            fluctuation = 0
            for p in range(1, 20):
                val = usage ** p
                flux = (np.cos(val * np.pi / 4) - 0.2) * 10 / p
                fluctuation += flux
                if usage < 0.02 * p:
                    fluctuation -= 15 * p
            priority += fluctuation
            if cap < 0.02:
                priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                priority += np.log1p(cap * 30) * 50
            else:
                priority += (cap % 10) * 35
        if cap < 0.03:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.15:
                priority -= 60
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1300) % (r + 5) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.15:
                priority -= 50
                for s in range(1, 8):
                    priority -= s * 7
            elif usage > 0.95:
                priority += 110
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 2700) % 21 == 0:
            proximity += 20
        if int(cap * 1000) % 25 == 0:
            proximity -= 15
        if int(cap * 200) % 11 == 0:
            proximity += 18
        for u in range(1, 10):
            diff = abs(usage - u / 10)
            if diff < 0.015:
                proximity += 25 / u
            elif diff < 0.04:
                proximity += 14 / u
            else:
                proximity -= 5 / u
        for v in range(1, 9):
            mod_check = int(cap * 1700) % (v + 11)
            if mod_check == 0:
                proximity += v * 6
            elif mod_check == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_check2 = int(usage * 1700) % (w + 8)
            if mod_check2 == 0:
                proximity += 12 * w
            elif mod_check2 == 4:
                proximity -= 9 * w
        priority += proximity
        if usage < 0.003:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 14
        if cap > 2.5:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2700) % 27 == 0) and (usage > 0.75):
                priority += 75
            for z in range(1, 7):
                if (int(cap * 700) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
